import { useState, useCallback } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Button,
  Icon,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: Task[];
  columns?: Column[];
  onTaskUpdate?: (payload: { action: string; taskId?: string; data?: unknown }) => void;
}

const DEFAULT_TASKS: Task[] = [
  { id: '1', title: 'Design landing page', priority: 'high', assignee: 'JD', column: 'todo', dueDate: '2024-01-15' },
  { id: '2', title: 'Set up API endpoints', priority: 'high', assignee: 'AB', column: 'in-progress', dueDate: '2024-01-12' },
  { id: '3', title: 'Write documentation', priority: 'medium', assignee: 'CD', column: 'done', dueDate: '2024-01-10' },
  { id: '4', title: 'Fix login bug', priority: 'high', assignee: 'EF', column: 'todo' },
  { id: '5', title: 'Database optimization', priority: 'medium', assignee: 'GH', column: 'in-progress' },
];

const DEFAULT_COLUMNS: Column[] = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' },
];

const getPriorityColor = (p?: string): 'error' | 'warning' | 'info' =>
  p === 'high' ? 'error' : p === 'medium' ? 'warning' : 'info';

const formatDate = (d?: string) => d ? new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : '';

const generateId = (): string => {
  const timestamp = Date.now();
  return 'task-' + String(timestamp);
};

interface TaskCardProps {
  task: Task;
  columns: Column[];
  onEdit: (t: Task) => void;
  onMove: (id: string, col: string) => void;
}

function TaskCard({ task, columns, onEdit, onMove }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [title, setTitle] = useState(task.title || '');

  const save = () => {
    if (title.trim()) {
      onEdit({ ...task, title });
      setIsEditing(false);
    }
  };

  const handleKey = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') save();
    else if (e.key === 'Escape') setIsEditing(false);
  };

  const initials = task.assignee || '';

  return (
    <Card padding={12} shadow="sm" border style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
      <Stack direction="vertical" gap={8}>
        {isEditing ? (
          <div>
            <Text variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
              Task Title
            </Text>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.currentTarget.value)}
              onKeyDown={handleKey}
              placeholder="Title"
              autoFocus
              style={{
                width: '100%',
                padding: 'var(--ggui-spacing-2, 8px)',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                fontSize: 'var(--ggui-font-size-sm, 14px)',
                fontFamily: 'inherit',
              }}
            />
          </div>
        ) : (
          <Row justify="between" align="start" gap={4}>
            <Text weight="medium" style={{ flex: 1, cursor: 'pointer' }} onDoubleClick={() => setIsEditing(true)}>
              {task.title || 'Untitled'}
            </Text>
            <Button variant="ghost" size="xs" onClick={() => setIsEditing(true)}>
              Edit
            </Button>
          </Row>
        )}

        <Row gap={6} wrap>
          <Badge variant={getPriorityColor(task.priority)} size="sm" pill>
            {(task.priority || 'low').charAt(0).toUpperCase() + (task.priority || 'low').slice(1)}
          </Badge>
          {initials && (
            <div
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: '20px',
                height: '20px',
                borderRadius: '50%',
                backgroundColor: 'var(--ggui-color-primary-500, #0ea5e9)',
                color: 'white',
                fontSize: '10px',
                fontWeight: 'bold',
              }}
              title={'Assigned to ' + initials}
            >
              {initials}
            </div>
          )}
          {task.dueDate && <Text variant="caption">{formatDate(task.dueDate)}</Text>}
        </Row>

        <Select
          label="Move"
          value={task.column || 'todo'}
          onChange={(col) => onMove(task.id || '', col)}
          options={columns.map((c) => ({ value: c.id || '', label: '→ ' + (c.name || 'Unknown') }))}
        />

        {isEditing && (
          <Row gap={4}>
            <Button variant="primary" size="xs" onClick={save}>
              Save
            </Button>
            <Button variant="outline" size="xs" onClick={() => setIsEditing(false)}>
              Cancel
            </Button>
          </Row>
        )}
      </Stack>
    </Card>
  );
}

interface ColProps {
  col: Column;
  tasks: Task[];
  allCols: Column[];
  onEdit: (t: Task) => void;
  onMove: (id: string, col: string) => void;
  onAdd: (col: string) => void;
}

function ColumnView({ col, tasks, allCols, onEdit, onMove, onAdd }: ColProps) {
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newPri, setNewPri] = useState('medium');

  const add = () => {
    if (newTitle.trim()) {
      onAdd(col.id || '');
      setNewTitle('');
      setNewPri('medium');
      setShowAdd(false);
    }
  };

  const handleKey = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') add();
    else if (e.key === 'Escape') setShowAdd(false);
  };

  return (
    <div
      style={{
        flex: 1,
        minWidth: '300px',
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        padding: 'var(--ggui-spacing-4, 16px)',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <div style={{ marginBottom: 'var(--ggui-spacing-4, 16px)', paddingBottom: 'var(--ggui-spacing-3, 12px)', borderBottom: '2px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="vertical" gap={2}>
          <Text variant="h3" weight="semibold">
            {col.name}
          </Text>
          <Text variant="caption">{tasks.length} task{tasks.length !== 1 ? 's' : ''}</Text>
        </Stack>
      </div>

      <div style={{ flex: 1, overflowY: 'auto', marginBottom: 'var(--ggui-spacing-3, 12px)', minHeight: '200px' }}>
        {tasks.length === 0 ? (
          <Text variant="caption" align="center" style={{ padding: 'var(--ggui-spacing-6, 24px) 0', display: 'block' }}>
            No tasks
          </Text>
        ) : (
          tasks.map((task) => (
            <TaskCard key={task.id} task={task} columns={allCols} onEdit={onEdit} onMove={onMove} />
          ))
        )}
      </div>

      {!showAdd ? (
        <Button variant="outline" size="sm" fullWidth leftIcon={<Icon name="plus" size={16} />} onClick={() => setShowAdd(true)}>
          Add Task
        </Button>
      ) : (
        <Card padding={12} shadow="sm" border style={{ borderColor: 'var(--ggui-color-primary-200, #bae6fd)' }}>
          <Stack direction="vertical" gap={8}>
            <div>
              <Text variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
                Title
              </Text>
              <input
                type="text"
                placeholder="Task title"
                value={newTitle}
                onChange={(e) => setNewTitle(e.currentTarget.value)}
                onKeyDown={handleKey}
                autoFocus
                style={{
                  width: '100%',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                  fontFamily: 'inherit',
                }}
              />
            </div>
            <Select label="Priority" value={newPri} onChange={setNewPri} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} />
            <Row gap={6}>
              <Button variant="primary" size="sm" onClick={add} disabled={!newTitle.trim()} fullWidth>
                Add
              </Button>
              <Button variant="outline" size="sm" onClick={() => setShowAdd(false)} fullWidth>
                Cancel
              </Button>
            </Row>
          </Stack>
        </Card>
      )}
    </div>
  );
}

export default function GeneratedComponent({ tasks = DEFAULT_TASKS, columns = DEFAULT_COLUMNS, onTaskUpdate }: Props) {
  const [allTasks, setAllTasks] = useState<Task[]>(tasks);

  const handleEdit = useCallback(
    (updatedTask: Task) => {
      setAllTasks((prev) => prev.map((t) => (t.id === updatedTask.id ? updatedTask : t)));
      onTaskUpdate?.({ action: 'edit', taskId: updatedTask.id, data: updatedTask });
    },
    [onTaskUpdate]
  );

  const handleMove = useCallback(
    (taskId: string, columnId: string) => {
      setAllTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: columnId } : t)));
      onTaskUpdate?.({ action: 'move', taskId, data: { columnId } });
    },
    [onTaskUpdate]
  );

  const handleAdd = useCallback(
    (columnId: string) => {
      const newId = generateId();
      const newTask: Task = { id: newId, title: 'New Task', priority: 'medium', column: columnId };
      setAllTasks((prev) => [...prev, newTask]);
      onTaskUpdate?.({ action: 'create', taskId: newId, data: newTask });
    },
    [onTaskUpdate]
  );

  const total = allTasks.length;
  const done = allTasks.filter((t) => t.column === 'done').length;

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="vertical" gap={24}>
        <Card padding={16} shadow="sm" border style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', borderColor: 'var(--ggui-color-primary-200, #bae6fd)' }}>
          <Stack direction="vertical" gap={4}>
            <Text variant="h3" weight="semibold">
              Task Summary
            </Text>
            <Row gap={24}>
              <div>
                <Text variant="caption">Total Tasks</Text>
                <Text variant="h2" weight="bold">
                  {total}
                </Text>
              </div>
              <Divider orientation="vertical" margin={0} />
              <div>
                <Text variant="caption">Completed</Text>
                <Text variant="h2" weight="bold">
                  {done}
                </Text>
              </div>
              <Divider orientation="vertical" margin={0} />
              <div>
                <Text variant="caption">Rate</Text>
                <Text variant="h2" weight="bold">
                  {total > 0 ? Math.round((done / total) * 100) : 0}%
                </Text>
              </div>
            </Row>
          </Stack>
        </Card>

        <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-2, 8px)' }}>
          {columns.map((column) => {
            const colTasks = allTasks.filter((t) => t.column === column.id);
            return <ColumnView key={column.id} col={column} tasks={colTasks} allCols={columns} onEdit={handleEdit} onMove={handleMove} onAdd={handleAdd} />;
          })}
        </div>
      </Stack>
    </Container>
  );
}
